final:
module t_flip_flop(  
    input wire clk,  
    input wire obf_CE,  
    input wire T,  
    output reg Q  
);  

    always @(posedge clk) begin  
        if (obf_CE) begin  
            if (T)  
                Q <= ~Q;  
        end  
    end  

    initial begin  
        Q = 0;  
    end  
endmodule
